import{_ as e,o as i,c as o,a2 as n}from"./chunks/framework.OWFDNrRT.js";const h=JSON.parse('{"title":"ADR-006: Domain Plugin Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-006-domain-plugin-architecture.md","filePath":"adr/ADR-006-domain-plugin-architecture.md","lastUpdated":1773460793000}'),r={name:"adr/ADR-006-domain-plugin-architecture.md"};function t(s,a,l,c,d,u){return i(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="adr-006-domain-plugin-architecture" tabindex="-1">ADR-006: Domain Plugin Architecture <a class="header-anchor" href="#adr-006-domain-plugin-architecture" aria-label="Permalink to &quot;ADR-006: Domain Plugin Architecture&quot;">​</a></h1><p><strong>Status</strong>: Accepted <strong>Date</strong>: 2026-03-09 <strong>Deciders</strong>: kooshapari</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>If warfare-specific assumptions are baked into core, the framework becomes useless for economy mods, UI mods, scenario mods, etc. The framework must support &quot;full modding range.&quot;</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>The framework uses <strong>domain plugins</strong> to extend capabilities without bloating core.</p><h3 id="core-framework" tabindex="-1">Core Framework <a class="header-anchor" href="#core-framework" aria-label="Permalink to &quot;Core Framework&quot;">​</a></h3><p>Only generic primitives: registries, pack loader, schema validator, override model, debug surfaces, logging.</p><h3 id="domain-plugin-warfare" tabindex="-1">Domain Plugin: Warfare <a class="header-anchor" href="#domain-plugin-warfare" aria-label="Permalink to &quot;Domain Plugin: Warfare&quot;">​</a></h3><p>Adds: factions, doctrines, combat unit classes, wave logic, weapons/projectile families, battlefield roles.</p><h3 id="domain-plugin-economy" tabindex="-1">Domain Plugin: Economy <a class="header-anchor" href="#domain-plugin-economy" aria-label="Permalink to &quot;Domain Plugin: Economy&quot;">​</a></h3><p>Adds: production chains, worker rules, resource tuning, taxation/upkeep/progression.</p><h3 id="domain-plugin-scenario" tabindex="-1">Domain Plugin: Scenario <a class="header-anchor" href="#domain-plugin-scenario" aria-label="Permalink to &quot;Domain Plugin: Scenario&quot;">​</a></h3><p>Adds: mission events, triggers, objectives, narrative scripting.</p><h3 id="domain-plugin-ui" tabindex="-1">Domain Plugin: UI <a class="header-anchor" href="#domain-plugin-ui" aria-label="Permalink to &quot;Domain Plugin: UI&quot;">​</a></h3><p>Adds: HUD injection, inspector overlays, faction skinning, custom tooltips.</p><h3 id="plugin-contract" tabindex="-1">Plugin Contract <a class="header-anchor" href="#plugin-contract" aria-label="Permalink to &quot;Plugin Contract&quot;">​</a></h3><p>Each domain plugin:</p><ul><li>Registers its own registry types with core</li><li>Provides its own schemas</li><li>Has its own validation rules</li><li>Can extend the pack manifest format</li><li>Must not depend on other domain plugins (only on core)</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>Warfare is a plugin, not hardcoded</li><li>New domains added without modifying core</li><li>Domain-specific packs only load when their domain plugin is active</li><li>Clean separation of concerns</li><li>Each domain plugin has its own test suite</li></ul>',21)])])}const p=e(r,[["render",t]]);export{h as __pageData,p as default};
